import{b as t,a as e,_ as i}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as l,o as r,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"인증 관리와 로그인 기기 관리","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Safety/authentication-and-login-devices.md","filePath":"ko-KR/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),n={name:"ko-KR/Safety/authentication-and-login-devices.md"};function h(s,a,c,p,_,u){return r(),o("div",null,[...a[0]||(a[0]=[d('<h1 id="인증-관리와-로그인-기기-관리" tabindex="-1">인증 관리와 로그인 기기 관리 <a class="header-anchor" href="#인증-관리와-로그인-기기-관리" aria-label="Permalink to &quot;인증 관리와 로그인 기기 관리&quot;">​</a></h1><p>인증 관리에서는 관리자 화면과 사용자 페이지의 로그인 방식, 로그인된 기기, 접근 상태를 확인할 수 있습니다.</p><h2 id="관리자-로그인" tabindex="-1">관리자 로그인 <a class="header-anchor" href="#관리자-로그인" aria-label="Permalink to &quot;관리자 로그인&quot;">​</a></h2><p>관리자는 관리자 로그인 화면을 통해 ImgBed 설정과 파일 관리로 들어갑니다.</p><p><img src="'+t+'" alt="관리자 로그인" loading="lazy"></p><p>관리자 계정은 강한 권한을 가지므로 비밀번호와 인증 정보는 안전하게 관리해야 합니다.</p><h2 id="사용자-로그인" tabindex="-1">사용자 로그인 <a class="header-anchor" href="#사용자-로그인" aria-label="Permalink to &quot;사용자 로그인&quot;">​</a></h2><p>사용자용 로그인 화면도 제공됩니다.</p><p><img src="'+e+'" alt="사용자 로그인" loading="lazy"></p><p>공개 업로드나 제한 공개 기능을 운영한다면 사용자 로그인을 함께 사용해 누가 작업했는지 추적하기 쉬워집니다.</p><h2 id="인증-관리-화면" tabindex="-1">인증 관리 화면 <a class="header-anchor" href="#인증-관리-화면" aria-label="Permalink to &quot;인증 관리 화면&quot;">​</a></h2><p>인증 관리 화면에서는 로그인 상태와 기기 정보를 확인할 수 있습니다.</p><p><img src="'+i+'" alt="인증 관리" loading="lazy"></p><h2 id="로그인-기기에서-확인할-항목" tabindex="-1">로그인 기기에서 확인할 항목 <a class="header-anchor" href="#로그인-기기에서-확인할-항목" aria-label="Permalink to &quot;로그인 기기에서 확인할 항목&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>로그인 기기</td><td>현재 로그인된 기기 확인</td></tr><tr><td>IP / 위치</td><td>어디에서 로그인했는지 참고</td></tr><tr><td>마지막 접근</td><td>최근에 사용된 기기인지 확인</td></tr><tr><td>해제</td><td>불필요하거나 의심스러운 로그인 세션 제거</td></tr></tbody></table><h2 id="의심스러운-로그인을-발견하면" tabindex="-1">의심스러운 로그인을 발견하면 <a class="header-anchor" href="#의심스러운-로그인을-발견하면" aria-label="Permalink to &quot;의심스러운 로그인을 발견하면&quot;">​</a></h2><ol><li>해당 기기의 로그인을 해제합니다.</li><li>관리자 비밀번호와 관련 토큰을 변경합니다.</li><li>Cloudflare, GitHub, 저장 채널의 인증 정보도 확인합니다.</li><li>필요하면 API Token을 재발급합니다.</li></ol><h2 id="운영-팁" tabindex="-1">운영 팁 <a class="header-anchor" href="#운영-팁" aria-label="Permalink to &quot;운영 팁&quot;">​</a></h2><ul><li>공용 PC에서는 로그인 상태를 유지하지 마세요.</li><li>관리자 권한 계정은 최소한으로 유지합니다.</li><li>로그인 기기 목록을 주기적으로 확인합니다.</li><li>오래된 세션이나 쓰지 않는 기기는 삭제합니다.</li></ul>',19)])])}const q=l(n,[["render",h]]);export{f as __pageData,q as default};
